angularMaterialOverrides.scssVariables:
/* === DMS Design System — paste into styles.scss === */
@import url('https://fonts.googleapis.com/css2?family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600&family=DM+Mono:wght@400;500&display=swap');

:root {
  /* Canvas */
  --dms-canvas: #F4F3F0;
  /* Cards */
  --dms-card: #FFFFFF;
  --dms-card-border: rgba(0,0,0,0.06);
  --dms-card-radius: 20px;
  --dms-card-shadow: 0 1px 3px rgba(0,0,0,0.04), 0 4px 12px rgba(0,0,0,0.04);
  --dms-card-hover-shadow: 0 2px 8px rgba(0,0,0,0.06), 0 8px 24px rgba(0,0,0,0.06);
  /* Accent */
  --dms-accent: #E85D3A;
  --dms-accent-hover: #D44F2E;
  --dms-accent-light: #FAE8E3;
  --dms-accent-mid: #F4C4B8;
  --dms-accent-dark: #A33320;
  /* Text */
  --dms-text-primary: #111110;
  --dms-text-secondary: #6B6B68;
  --dms-text-tertiary: #A8A8A4;
  --dms-text-inverse: #FFFFFF;
  /* Typography */
  --dms-font: 'DM Sans', sans-serif;
  --dms-mono: 'DM Mono', monospace;
  /* Radii */
  --dms-radius-xs: 4px;
  --dms-radius-sm: 8px;
  --dms-radius-md: 12px;
  --dms-radius-lg: 20px;
  --dms-radius-pill: 100px;
  /* Semantic status */
  --dms-success: #2EAA55;
  --dms-warning: #F59500;
  --dms-error: #C41C1C;
  --dms-info: #2B5BF5;
}

* { box-sizing: border-box; }
body {
  font-family: var(--dms-font);
  background: var(--dms-canvas);
  color: var(--dms-text-primary);
  margin: 0;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}
.mono { font-family: var(--dms-mono); }
.tabular { font-variant-numeric: tabular-nums; font-feature-settings: 'tnum' 1; }
